mapper.select:
SELECT DISTINCT ivl.item_id
FROM item_view_log ivl
WHERE ivl.user_id = #{userId}
ORDER BY ivl.view_time DESC
LIMIT #{limit}

SELECT ivl.user_id, COUNT(DISTINCT ivl.item_id) as view_count FROM item_view_log ivl WHERE ivl.user_id IN
#{userId}
GROUP BY ivl.user_id

SELECT o.user_id, COUNT(DISTINCT oi.item_id) as purchase_count FROM order_item oi JOIN orders o ON oi.order_id = o.id WHERE o.user_id IN
#{userId}
AND o.status = 'COMPLETED' GROUP BY o.user_id

SELECT o.user_id, COALESCE(SUM(o.total_amount), 0) as total_spent FROM orders o WHERE o.user_id IN
#{userId}
AND o.status = 'COMPLETED' GROUP BY o.user_id
